SELECT count(*) FROM cast_info, role_type, title, movie_keyword, char_name, keyword, name, kind_type WHERE cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND cast_info.person_role_id = char_name.id AND movie_keyword.keyword_id = keyword.id AND cast_info.person_id = name.id AND title.kind_id = kind_type.id;